// quizpage.js — batch-scored end-of-module quiz. Reuses the .quiz answer model
// (data from window.QUIZ, generated by tools/quiz-data.mjs) but grades a whole set
// at once instead of per-question like quiz.js. Driven by quiz.html.
(function () {
  var C = window.COURSE, QUIZ = window.QUIZ;
  if (!C || !QUIZ) return;
  var slug = location.pathname.split("/").slice(-2, -1)[0]; // courses/<slug>/quiz.html
  var params = new URLSearchParams(location.search);
  var mods = C.modules;

  function modOf(id) { return mods.filter(function (m) { return m.id === id; })[0]; }
  var mid = params.get("m");
  if (!QUIZ[mid]) mid = mods[0].id;
  var m = modOf(mid), qs = QUIZ[mid];

  var root = document.getElementById("quiz");
  var title = document.getElementById("quiztitle");
  title.innerHTML = '<span class="pill" style="background:' + m.color + '">Module ' + m.n + '</span> ' +
    m.title.replace(/^.*?—\s*/, "");
  document.title = "Module " + m.n + " Quiz · " + C.title;

  // best score chip
  var bestKey = "quiz:" + slug + ":" + mid;
  var best = null; try { best = localStorage.getItem(bestKey); } catch (e) {}
  if (best) document.getElementById("best").textContent = "Best so far: " + best;

  // render questions as radio groups
  qs.forEach(function (item, qi) {
    var card = document.createElement("div");
    card.className = "quiz qp";
    var q = document.createElement("p"); q.className = "q";
    q.innerHTML = (qi + 1) + ". " + item.q;
    card.appendChild(q);
    item.opts.forEach(function (opt, oi) {
      var id = "q" + qi + "o" + oi;
      var row = document.createElement("label");
      row.className = "qp-opt"; row.setAttribute("for", id);
      row.innerHTML = '<input type="radio" name="q' + qi + '" id="' + id + '" value="' + oi + '">' +
        '<span>' + opt + '</span>';
      card.appendChild(row);
    });
    var fb = document.createElement("p"); fb.className = "fb"; card.appendChild(fb);
    root.appendChild(card);
  });

  // submit + grade
  var submit = document.getElementById("submit");
  submit.addEventListener("click", function () {
    var score = 0, cards = root.querySelectorAll(".quiz");
    qs.forEach(function (item, qi) {
      var card = cards[qi], fb = card.querySelector(".fb");
      var picked = card.querySelector('input[name="q' + qi + '"]:checked');
      var pi = picked ? +picked.value : -1;
      card.querySelectorAll(".qp-opt").forEach(function (row, oi) {
        row.querySelector("input").disabled = true;
        row.classList.toggle("correct", oi === item.a);
        if (oi === pi && pi !== item.a) row.classList.add("wrong");
      });
      if (pi === item.a) { score++; fb.textContent = "Correct. " + (item.why || ""); }
      else {
        fb.innerHTML = "Not quite. " + (item.why || "") +
          ' <a class="review-link" href="lessons/' + item.lesson + '.html">Review: Lesson ' +
          item.n + " — " + item.title + " →</a>";
      }
    });
    var line = score + " / " + qs.length;
    document.getElementById("score").textContent = "You scored " + line;
    if (!best || score > parseInt(best, 10)) {
      try { localStorage.setItem(bestKey, line); } catch (e) {}
      document.getElementById("best").textContent = "Best so far: " + line;
    }
    submit.disabled = true;
    document.getElementById("score").scrollIntoView({ behavior: matchMedia("(prefers-reduced-motion:reduce)").matches ? "auto" : "smooth", block: "center" });
  });

  // prev/next module switcher
  var idx = mods.indexOf(m);
  function navLink(el, target, label) {
    if (!target) { el.remove(); return; }
    el.href = "quiz.html?m=" + target.id;
    el.textContent = label.replace("%", "Module " + target.n);
  }
  navLink(document.getElementById("prevmod"), mods[idx - 1], "← %");
  navLink(document.getElementById("nextmod"), mods[idx + 1], "% →");
})();
